# ❌ ANTI-PATTERN: Naive retrieval without strategy
class CricketRAGAntiPattern:
    def answer_question(self, question):
        # Retrieves everything, no caching, no hybrid approach
        all_matches = self.vector_store.search(question, top_k=1000)
        context = ''.join([m['text'] for m in all_matches])
        # LLM drowns in irrelevant data
        return self.llm(f"{question}\n\n{context}")

# ✅ BEST PRACTICE: Hybrid retrieval with caching strategy
class CricketRAGBestPractice:
    def __init__(self):
        self.vector_cache = {}  # Cache frequent queries
        self.bm25_index = BM25Okapi(cricket_corpus)  # Lexical search
        self.vector_index = FAISS(cricket_embeddings)  # Semantic search

    def answer_question(self, question):
        # Check cache first
        cache_key = hash(question)
        if cache_key in self.vector_cache:
            context = self.vector_cache[cache_key]
        else:
            # Hybrid: combine BM25 keyword match + vector semantic match
            bm25_results = self.bm25_index.get_top_k(question, k=5)
            vector_results = self.vector_index.search(question, k=5)

            # Rerank by combining scores (BM25 for exact, vector for meaning)
            merged = self._rerank_hybrid(bm25_results, vector_results)
            context = '\n'.join([m['text'] for m in merged[:10]])
            self.vector_cache[cache_key] = context

        return self.llm(f"{question}\n\nContext:\n{context}")

    def _rerank_hybrid(self, bm25, vector):
        # Normalize scores and blend them
        return sorted(
            [(r, 0.4*s) for r, s in bm25] + [(r, 0.6*s) for r, s in vector],
            key=lambda x: x[1],
            reverse=True
        )
